from dataclasses import dataclass, field
from typing import List, Dict, Optional
from enum import Enum
from statistics import mean

class KirkpatrickLevel(Enum):
    REACTION = 1
    LEARNING = 2
    BEHAVIOUR = 3
    RESULTS = 4

@dataclass
class ReactionSurveyResult:
    respondent_id: str
    module_id: str
    relevance_score: float       # 1-5
    clarity_score: float         # 1-5
    confidence_score: float      # 1-5: how confident will this help your work?
    overall_score: float         # 1-5

    def composite(self) -> float:
        return mean([self.relevance_score, self.clarity_score,
                     self.confidence_score, self.overall_score])

@dataclass
class BehaviourObservation:
    employee_id: str
    role_family: str
    observation_date: str
    ai_tool_usage_days_per_week: float     # Average in preceding 2 weeks
    applies_verification_habits: bool      # Checks AI outputs against sources
    reports_ai_issues_proactively: bool    # Reports problems through proper channel
    observer: str
    notes: str = ""

    def behaviour_score(self) -> float:
        base = min(self.ai_tool_usage_days_per_week / 5 * 60, 60)
        base += 20 if self.applies_verification_habits else 0
        base += 20 if self.reports_ai_issues_proactively else 0
        return base

@dataclass
class TrainingEffectivenessDashboard:
    programme: str
    reaction_results: List[ReactionSurveyResult] = field(default_factory=list)
    behaviour_observations: List[BehaviourObservation] = field(default_factory=list)
    learning_pass_rate: Optional[float] = None   # from LMS assessment data

    def avg_reaction_score(self) -> Optional[float]:
        if not self.reaction_results:
            return None
        return mean(r.composite() for r in self.reaction_results)

    def behaviour_score_by_role(self) -> Dict[str, float]:
        by_role: Dict[str, List[float]] = {}
        for obs in self.behaviour_observations:
            by_role.setdefault(obs.role_family, []).append(obs.behaviour_score())
        return {role: mean(scores) for role, scores in by_role.items()}

    def low_behaviour_groups(self, threshold: float = 60.0) -> List[str]:
        return [role for role, score in self.behaviour_score_by_role().items()
                if score < threshold]

    def summary(self) -> str:
        lines = [
            f"Training Effectiveness: {self.programme}",
            f"L1 Reaction avg: {self.avg_reaction_score():.2f}/5.0"
            if self.avg_reaction_score() else "L1 Reaction: No data",
            f"L2 Learning pass rate: {self.learning_pass_rate:.0f}%"
            if self.learning_pass_rate else "L2 Learning: No data",
            "L3 Behaviour scores by role:",
        ]
        for role, score in self.behaviour_score_by_role().items():
            lines.append(f"  {role}: {score:.0f}/100")
        if self.low_behaviour_groups():
            lines.append(f"Groups needing behaviour support: {', '.join(self.low_behaviour_groups())}")
        return "\n".join(lines)

# Example
dashboard = TrainingEffectivenessDashboard("GenAI Customer Ops", learning_pass_rate=78.5)
dashboard.reaction_results = [
    ReactionSurveyResult("E01", "CSM01", 4.2, 3.8, 3.5, 4.0),
    ReactionSurveyResult("E02", "CSM01", 4.5, 4.2, 4.0, 4.3),
    ReactionSurveyResult("E03", "CSM01", 3.0, 3.5, 2.8, 3.2),
]
dashboard.behaviour_observations = [
    BehaviourObservation("E01", "Customer Success", "2025-09-30",
                         ai_tool_usage_days_per_week=3.5,
                         applies_verification_habits=True,
                         reports_ai_issues_proactively=False,
                         observer="Manager A"),
    BehaviourObservation("E04", "Legal Review", "2025-09-30",
                         ai_tool_usage_days_per_week=1.0,
                         applies_verification_habits=True,
                         reports_ai_issues_proactively=True,
                         observer="Manager B"),
]
print(dashboard.summary())
